1	/**
2	 * The Parlour — multi-turn conversation management apparatus.
3	 *
4	 * Manages two kinds of conversation:
5	 * - consult: a human talks to an anima
6	 * - convene: multiple animas hold a structured dialogue
7	 *
8	 * The Parlour orchestrates turns — it decides when and for whom to call
9	 * The Animator, and tracks conversation state in The Stacks. It does not
10	 * launch sessions itself (delegates to The Animator) or assemble prompts
11	 * (delegates to The Loom).
12	 *
13	 * See: docs/architecture/apparatus/parlour.md
14	 */
15	
16	import type { Plugin, StartupContext } from '@shardworks/nexus-core';
17	import { guild, generateId } from '@shardworks/nexus-core';
18	import type { StacksApi, Book, ReadOnlyBook, WhereCondition } from '@shardworks/stacks-apparatus';
19	import type { AnimatorApi, SessionResult, SessionChunk, SessionDoc } from '@shardworks/animator-apparatus';
20	import type { LoomApi } from '@shardworks/loom-apparatus';
21	
22	import type {
23	  ParlourApi,
24	  ConversationDoc,
25	  TurnDoc,
26	  ParticipantRecord,
27	  Participant,
28	  CreateConversationRequest,
29	  CreateConversationResult,
30	  TakeTurnRequest,
31	  TurnResult,
32	  ConversationChunk,
33	  ConversationSummary,
34	  ConversationDetail,
35	  TurnSummary,
36	  ListConversationsOptions,
37	} from './types.ts';
38	
39	import { conversationList, conversationShow, conversationEnd } from './tools/index.ts';
40	
41	// ── Helpers ──────────────────────────────────────────────────────────
42	
43	/**
44	 * Count anima turns in the conversation (for turn limit enforcement).
45	 * Human turns do not count toward the turn limit.
46	 */
47	async function countAnimaTurns(
48	  turns: ReadOnlyBook<TurnDoc>,
49	  conversationId: string,
50	): Promise<number> {
51	  return turns.count([
52	    ['conversationId', '=', conversationId],
53	    ['participantKind', '=', 'anima'],
54	  ]);
55	}
56	
57	/**
58	 * Count all turns in the conversation (for turnNumber assignment).
59	 */
60	async function countAllTurns(
61	  turns: ReadOnlyBook<TurnDoc>,
62	  conversationId: string,
63	): Promise<number> {
64	  return turns.count([
65	    ['conversationId', '=', conversationId],
66	  ]);
67	}
68	
69	/**
70	 * Get the most recent turn for a specific participant.
71	 */
72	async function getLastTurnForParticipant(
73	  turns: ReadOnlyBook<TurnDoc>,
74	  conversationId: string,
75	  participantId: string,
76	): Promise<TurnDoc | null> {
77	  const results = await turns.find({
78	    where: [
79	      ['conversationId', '=', conversationId],
80	      ['participantId', '=', participantId],
81	    ],
82	    orderBy: ['turnNumber', 'desc'],
83	    limit: 1,
84	  });
85	  return results[0] ?? null;
86	}
87	
88	/**
89	 * Get turns since a given turn number (exclusive), ordered ascending.
90	 */
91	async function getTurnsSince(
92	  turns: ReadOnlyBook<TurnDoc>,
93	  conversationId: string,
94	  afterTurnNumber: number,
95	): Promise<TurnDoc[]> {
96	  return turns.find({
97	    where: [
98	      ['conversationId', '=', conversationId],
99	      ['turnNumber', '>', afterTurnNumber],
100	    ],
101	    orderBy: ['turnNumber', 'asc'],
102	  });
103	}
104	
105	/**
106	 * Get all turns for a conversation, ordered by turnNumber ascending.
107	 */
108	async function getAllTurns(
109	  turns: ReadOnlyBook<TurnDoc>,
110	  conversationId: string,
111	): Promise<TurnDoc[]> {
112	  return turns.find({
113	    where: [
114	      ['conversationId', '=', conversationId],
115	    ],
116	    orderBy: ['turnNumber', 'asc'],
117	  });
118	}
119	
120	/**
121	 * Map ParticipantRecord[] to Participant[] (public projection).
122	 */
123	function toParticipants(records: ParticipantRecord[]): Participant[] {
124	  return records.map((r) => ({
125	    id: r.id,
126	    name: r.name,
127	    kind: r.kind,
128	  }));
129	}
130	
131	/**
132	 * Assemble the inter-turn message for a consult conversation.
133	 *
134	 * For consult, the pattern is simple: the human's message from the
135	 * TakeTurnRequest is passed directly as the prompt. If no message
136	 * is provided, the conversation topic is used as fallback (first turn).
137	 */
138	function assembleConsultMessage(
139	  request: TakeTurnRequest,
140	  conversation: ConversationDoc,
141	  isFirstTurn: boolean,
142	): string | undefined {
143	  if (request.message) return request.message;
144	  if (isFirstTurn && conversation.topic) return conversation.topic;
145	  return undefined;
146	}
147	
148	/**
149	 * Assemble the inter-turn message for a convene conversation.
150	 *
151	 * For convene, each participant needs to see what other participants said
152	 * since their last turn. This requires reading session transcripts, which
153	 * depends on session record artifacts that the Animator MVP does not produce.
154	 *
155	 * At MVP, this uses the human-readable messages stored in turn records,
156	 * which are adequate for human turns but cannot capture anima responses
157	 * (the Animator does not expose transcript text). Anima contributions
158	 * fall back to a placeholder.
159	 *
160	 * See: parlour-implementation-tracker.md § Gap #1
161	 */
162	async function assembleConveneMessage(
163	  turns: ReadOnlyBook<TurnDoc>,
164	  conversation: ConversationDoc,
165	  participantId: string,
166	  isFirstTurn: boolean,
167	): Promise<string | undefined> {
168	  if (isFirstTurn && conversation.topic) return conversation.topic;
169	
170	  // Get this participant's last turn to find intervening turns
171	  const lastTurn = await getLastTurnForParticipant(
172	    turns,
173	    conversation.id,
174	    participantId,
175	  );
176	
177	  if (!lastTurn) {
178	    // Never taken a turn — use topic
179	    return conversation.topic ?? undefined;
180	  }
181	
182	  // Get all turns since this participant's last turn
183	  const intervening = await getTurnsSince(
184	    turns,
185	    conversation.id,
186	    lastTurn.turnNumber,
187	  );
188	
189	  if (intervening.length === 0) return undefined;
190	
191	  // Assemble messages from other participants
192	  const lines: string[] = [];
193	  for (const turn of intervening) {
194	    if (turn.participantId === participantId) continue;
195	    if (turn.participantKind === 'human' && turn.message) {
196	      lines.push(`[${turn.participantName}]: ${turn.message}`);
197	    } else if (turn.participantKind === 'anima') {
198	      // Cannot extract anima response — Animator MVP has no transcript text.
199	      // Placeholder until session record artifacts or response capture is available.
200	      lines.push(`[${turn.participantName}]: [response not available]`);
201	    }
202	  }
203	
204	  return lines.length > 0 ? lines.join('\n\n') : undefined;
205	}
206	
207	// ── Apparatus factory ────────────────────────────────────────────────
208	
209	/**
210	 * Create the Parlour apparatus plugin.
211	 *
212	 * Returns a Plugin with:
213	 * - `requires: ['stacks', 'animator', 'loom']` — conversation orchestration
214	 * - `provides: ParlourApi` — the conversation management API
215	 * - `supportKit` — contributes `conversations` + `turns` books + management tools
216	 */
217	export function createParlour(): Plugin {
218	  let conversations: Book<ConversationDoc>;
219	  let turns: Book<TurnDoc>;
220	  let sessions: ReadOnlyBook<SessionDoc>;
221	
222	  const api: ParlourApi = {
223	    async create(request: CreateConversationRequest): Promise<CreateConversationResult> {
224	      const conversationId = generateId('conv');
225	
226	      // Build participant records
227	      const participants: ParticipantRecord[] = request.participants.map((decl) => ({
228	        id: generateId('part'),
229	        kind: decl.kind,
230	        name: decl.name,
231	        animaId: null, // No Roster yet — leave null at MVP
232	        providerSessionId: null,
233	      }));
234	
235	      // Write conversation document
236	      const doc: ConversationDoc = {
237	        id: conversationId,
238	        status: 'active',
239	        kind: request.kind,
240	        topic: request.topic ?? null,
241	        turnLimit: request.turnLimit ?? null,
242	        createdAt: new Date().toISOString(),
243	        endedAt: null,
244	        eventId: request.eventId ?? null,
245	        participants,
246	        cwd: request.cwd,
247	      };
248	
249	      await conversations.put(doc);
250	
251	      return {
252	        conversationId,
253	        participants: toParticipants(participants),
254	      };
255	    },
256	
257	    async takeTurn(request: TakeTurnRequest): Promise<TurnResult> {
258	      // 1. Read conversation state
259	      const conv = await conversations.get(request.conversationId);
260	      if (!conv) {
261	        throw new Error(`Conversation "${request.conversationId}" not found.`);
262	      }
263	      if (conv.status !== 'active') {
264	        throw new Error(
265	          `Conversation "${request.conversationId}" is ${conv.status}, not active.`,
266	        );
267	      }
268	
269	      // Find the participant
270	      const participant = conv.participants.find((p) => p.id === request.participantId);
271	      if (!participant) {
272	        throw new Error(
273	          `Participant "${request.participantId}" not found in conversation "${request.conversationId}".`,
274	        );
275	      }
276	
277	      // 2. Determine turn number
278	      const totalTurns = await countAllTurns(turns, conv.id);
279	      const turnNumber = totalTurns + 1;
280	
281	      // 3. Check turn limit (anima turns only)
282	      if (participant.kind === 'anima' && conv.turnLimit !== null) {
283	        const animaTurns = await countAnimaTurns(turns, conv.id);
284	        if (animaTurns >= conv.turnLimit) {
285	          throw new Error(
286	            `Conversation "${conv.id}" has reached its turn limit of ${conv.turnLimit}.`,
287	          );
288	        }
289	      }
290	
291	      const startedAt = new Date().toISOString();
292	
293	      if (participant.kind === 'human') {
294	        // Human turn — record the message, no session launched
295	        const turnId = generateId('turn', 6);
296	        await turns.put({
297	          id: turnId,
298	          conversationId: conv.id,
299	          turnNumber,
300	          participantId: participant.id,
301	          participantName: participant.name,
302	          participantKind: 'human',
303	          message: request.message ?? null,
304	          sessionId: null,
305	          startedAt,
306	          endedAt: new Date().toISOString(),
307	        });
308	
309	        return {
310	          sessionResult: null,
311	          turnNumber,
312	          conversationActive: true,
313	        };
314	      }
315	
316	      // Anima turn — weave context and call the Animator
317	      const loom = guild().apparatus<LoomApi>('loom');
318	      const animator = guild().apparatus<AnimatorApi>('animator');
319	
320	      // Determine if this is the participant's first turn
321	      const lastTurn = await getLastTurnForParticipant(turns, conv.id, participant.id);
322	      const isFirstTurn = lastTurn === null;
323	
324	      // Assemble the message for this turn
325	      let message: string | undefined;
326	      if (conv.kind === 'consult') {
327	        message = assembleConsultMessage(request, conv, isFirstTurn);
328	      } else {
329	        message = await assembleConveneMessage(turns, conv, participant.id, isFirstTurn);
330	      }
331	
332	      // Weave anima context via The Loom
333	      const context = await loom.weave({ role: undefined });
334	
335	      // Call The Animator
336	      const { result: resultPromise } = animator.animate({
337	        context,
338	        prompt: message,
339	        cwd: conv.cwd,
340	        conversationId: participant.providerSessionId ?? undefined,
341	        metadata: {
342	          trigger: 'parlour',
343	          conversationId: conv.id,
344	          turnNumber,
345	          participantId: participant.id,
346	        },
347	      });
348	
349	      const sessionResult = await resultPromise;
350	
351	      // Update participant's providerSessionId for --resume
352	      const updatedParticipants = conv.participants.map((p) =>
353	        p.id === participant.id
354	          ? { ...p, providerSessionId: sessionResult.providerSessionId ?? p.providerSessionId }
355	          : p,
356	      );
357	      await conversations.patch(conv.id, { participants: updatedParticipants });
358	
359	      // Record the turn
360	      const turnId = generateId('turn', 6);
361	      await turns.put({
362	        id: turnId,
363	        conversationId: conv.id,
364	        turnNumber,
365	        participantId: participant.id,
366	        participantName: participant.name,
367	        participantKind: 'anima',
368	        message: message ?? null,
369	        sessionId: sessionResult.id,
370	        startedAt,
371	        endedAt: new Date().toISOString(),
372	      });
373	
374	      // Check if turn limit reached → auto-conclude
375	      let conversationActive = true;
376	      if (conv.turnLimit !== null) {
377	        const animaTurns = await countAnimaTurns(turns, conv.id);
378	        if (animaTurns >= conv.turnLimit) {
379	          await this.end(conv.id, 'concluded');
380	          conversationActive = false;
381	        }
382	      }
383	
384	      return {
385	        sessionResult,
386	        turnNumber,
387	        conversationActive,
388	      };
389	    },
390	
391	    takeTurnStreaming(request: TakeTurnRequest): {
392	      chunks: AsyncIterable<ConversationChunk>;
393	      result: Promise<TurnResult>;
394	    } {
395	      type HumanResolved = { kind: 'human'; turnResult: TurnResult };
396	      type AnimaResolved = {
397	        kind: 'anima';
398	        animatorChunks: AsyncIterable<SessionChunk>;
399	        animatorResult: Promise<SessionResult>;
400	        conv: ConversationDoc;
401	        participant: ParticipantRecord;
402	        turnNumber: number;
403	        startedAt: string;
404	        message: string | undefined;
405	      };
406	      type StreamResolved = HumanResolved | AnimaResolved;
407	
408	      // Read conversation state and launch the turn.
409	      // We need to return synchronously, so wrap the async flow.
410	      const deferred: Promise<StreamResolved> = (async (): Promise<StreamResolved> => {
411	        // 1. Read conversation state
412	        const conv = await conversations.get(request.conversationId);
413	        if (!conv) {
414	          throw new Error(`Conversation "${request.conversationId}" not found.`);
415	        }
416	        if (conv.status !== 'active') {
417	          throw new Error(
418	            `Conversation "${request.conversationId}" is ${conv.status}, not active.`,
419	          );
420	        }
421	
422	        // Find the participant
423	        const participant = conv.participants.find((p) => p.id === request.participantId);
424	        if (!participant) {
425	          throw new Error(
426	            `Participant "${request.participantId}" not found in conversation "${request.conversationId}".`,
427	          );
428	        }
429	
430	        // Human turns don't stream — delegate to non-streaming path
431	        if (participant.kind === 'human') {
432	          const turnResult = await this.takeTurn(request);
433	          return { kind: 'human', turnResult };
434	        }
435	
436	        // 2. Determine turn number
437	        const totalTurns = await countAllTurns(turns, conv.id);
438	        const turnNumber = totalTurns + 1;
439	
440	        // 3. Check turn limit
441	        if (conv.turnLimit !== null) {
442	          const animaTurns = await countAnimaTurns(turns, conv.id);
443	          if (animaTurns >= conv.turnLimit) {
444	            throw new Error(
445	              `Conversation "${conv.id}" has reached its turn limit of ${conv.turnLimit}.`,
446	            );
447	          }
448	        }
449	
450	        const startedAt = new Date().toISOString();
451	
452	        const loom = guild().apparatus<LoomApi>('loom');
453	        const animator = guild().apparatus<AnimatorApi>('animator');
454	
455	        // Determine if first turn
456	        const lastTurn = await getLastTurnForParticipant(turns, conv.id, participant.id);
457	        const isFirstTurn = lastTurn === null;
458	
459	        // Assemble message
460	        let message: string | undefined;
461	        if (conv.kind === 'consult') {
462	          message = assembleConsultMessage(request, conv, isFirstTurn);
463	        } else {
464	          message = await assembleConveneMessage(turns, conv, participant.id, isFirstTurn);
465	        }
466	
467	        // Weave + animate with streaming
468	        const context = await loom.weave({ role: undefined });
469	        const handle = animator.animate({
470	          context,
471	          prompt: message,
472	          cwd: conv.cwd,
473	          conversationId: participant.providerSessionId ?? undefined,
474	          metadata: {
475	            trigger: 'parlour',
476	            conversationId: conv.id,
477	            turnNumber,
478	            participantId: participant.id,
479	          },
480	          streaming: true,
481	        });
482	
483	        return {
484	          kind: 'anima',
485	          animatorChunks: handle.chunks,
486	          animatorResult: handle.result,
487	          conv,
488	          participant,
489	          turnNumber,
490	          startedAt,
491	          message,
492	        };
493	      })();
494	
495	      async function* streamChunks(): AsyncIterable<ConversationChunk> {
496	        const resolved = await deferred;
497	        // Human turn — no chunks
498	        if (resolved.kind === 'human') return;
499	
500	        const { animatorChunks, animatorResult } = resolved;
501	
502	        // Pipe through Animator chunks
503	        yield* animatorChunks;
504	
505	        // Wait for final result to emit turn_complete
506	        const sessionResult = await animatorResult;
507	        yield {
508	          type: 'turn_complete' as const,
509	          turnNumber: resolved.turnNumber,
510	          costUsd: sessionResult.costUsd,
511	        };
512	      }
513	
514	      const result = (async (): Promise<TurnResult> => {
515	        const resolved = await deferred;
516	
517	        // Human turn — already handled
518	        if (resolved.kind === 'human') return resolved.turnResult;
519	
520	        const { animatorResult, conv, participant, turnNumber, startedAt, message } = resolved;
521	        const sessionResult = await animatorResult;
522	
523	        // Update providerSessionId
524	        const updatedParticipants = conv.participants.map((p) =>
525	          p.id === participant.id
526	            ? { ...p, providerSessionId: sessionResult.providerSessionId ?? p.providerSessionId }
527	            : p,
528	        );
529	        await conversations.patch(conv.id, { participants: updatedParticipants });
530	
531	        // Record turn
532	        const turnId = generateId('turn', 6);
533	        await turns.put({
534	          id: turnId,
535	          conversationId: conv.id,
536	          turnNumber,
537	          participantId: participant.id,
538	          participantName: participant.name,
539	          participantKind: 'anima',
540	          message: message ?? null,
541	          sessionId: sessionResult.id,
542	          startedAt,
543	          endedAt: new Date().toISOString(),
544	        });
545	
546	        // Check turn limit
547	        let conversationActive = true;
548	        if (conv.turnLimit !== null) {
549	          const animaTurns = await countAnimaTurns(turns, conv.id);
550	          if (animaTurns >= conv.turnLimit) {
551	            await api.end(conv.id, 'concluded');
552	            conversationActive = false;
553	          }
554	        }
555	
556	        return { sessionResult, turnNumber, conversationActive };
557	      })();
558	
559	      return { chunks: streamChunks(), result };
560	    },
561	
562	    async nextParticipant(conversationId: string): Promise<Participant | null> {
563	      const conv = await conversations.get(conversationId);
564	      if (!conv || conv.status !== 'active') return null;
565	
566	      // Check turn limit
567	      if (conv.turnLimit !== null) {
568	        const animaTurns = await countAnimaTurns(turns, conv.id);
569	        if (animaTurns >= conv.turnLimit) return null;
570	      }
571	
572	      if (conv.kind === 'consult') {
573	        // For consult: always return the anima participant
574	        const anima = conv.participants.find((p) => p.kind === 'anima');
575	        if (!anima) return null;
576	        return { id: anima.id, name: anima.name, kind: anima.kind };
577	      }
578	
579	      // For convene: round-robin among all participants
580	      const totalTurns = await countAllTurns(turns, conv.id);
581	      const nextIndex = totalTurns % conv.participants.length;
582	      const next = conv.participants[nextIndex];
583	      return { id: next.id, name: next.name, kind: next.kind };
584	    },
585	
586	    async end(conversationId: string, reason?: 'concluded' | 'abandoned'): Promise<void> {
587	      const conv = await conversations.get(conversationId);
588	      if (!conv) {
589	        throw new Error(`Conversation "${conversationId}" not found.`);
590	      }
591	      // Idempotent — no error if already ended
592	      if (conv.status !== 'active') return;
593	
594	      await conversations.patch(conversationId, {
595	        status: reason ?? 'concluded',
596	        endedAt: new Date().toISOString(),
597	      });
598	    },
599	
600	    async list(options?: ListConversationsOptions): Promise<ConversationSummary[]> {
601	      const where: WhereCondition[] = [];
602	      if (options?.status) where.push(['status', '=', options.status]);
603	      if (options?.kind) where.push(['kind', '=', options.kind]);
604	
605	      const convs = await conversations.find({
606	        where: where.length > 0 ? where : undefined,
607	        orderBy: ['createdAt', 'desc'],
608	        limit: options?.limit ?? 20,
609	      });
610	
611	      // Build summaries with turn counts and cost aggregation
612	      const summaries: ConversationSummary[] = [];
613	      for (const conv of convs) {
614	        const convTurns = await getAllTurns(turns, conv.id);
615	        const sessionIds = convTurns
616	          .map((t) => t.sessionId)
617	          .filter((id): id is string => id !== null);
618	
619	        // Aggregate cost from session records
620	        let totalCostUsd = 0;
621	        for (const sessionId of sessionIds) {
622	          const session = await sessions.get(sessionId);
623	          if (session?.costUsd) totalCostUsd += session.costUsd;
624	        }
625	
626	        summaries.push({
627	          id: conv.id,
628	          status: conv.status,
629	          kind: conv.kind,
630	          topic: conv.topic,
631	          turnLimit: conv.turnLimit,
632	          createdAt: conv.createdAt,
633	          endedAt: conv.endedAt,
634	          participants: toParticipants(conv.participants),
635	          turnCount: convTurns.length,
636	          totalCostUsd,
637	        });
638	      }
639	
640	      return summaries;
641	    },
642	
643	    async show(conversationId: string): Promise<ConversationDetail | null> {
644	      const conv = await conversations.get(conversationId);
645	      if (!conv) return null;
646	
647	      const convTurns = await getAllTurns(turns, conv.id);
648	      const sessionIds = convTurns
649	        .map((t) => t.sessionId)
650	        .filter((id): id is string => id !== null);
651	
652	      // Aggregate cost
653	      let totalCostUsd = 0;
654	      for (const sessionId of sessionIds) {
655	        const session = await sessions.get(sessionId);
656	        if (session?.costUsd) totalCostUsd += session.costUsd;
657	      }
658	
659	      // Build turn summaries
660	      const turnSummaries: TurnSummary[] = convTurns.map((t) => ({
661	        sessionId: t.sessionId,
662	        turnNumber: t.turnNumber,
663	        participant: t.participantName,
664	        message: t.message,
665	        startedAt: t.startedAt,
666	        endedAt: t.endedAt,
667	      }));
668	
669	      return {
670	        id: conv.id,
671	        status: conv.status,
672	        kind: conv.kind,
673	        topic: conv.topic,
674	        turnLimit: conv.turnLimit,
675	        createdAt: conv.createdAt,
676	        endedAt: conv.endedAt,
677	        participants: toParticipants(conv.participants),
678	        turnCount: convTurns.length,
679	        totalCostUsd,
680	        turns: turnSummaries,
681	      };
682	    },
683	  };
684	
685	  return {
686	    apparatus: {
687	      requires: ['stacks', 'animator', 'loom'],
688	
