1	/**
2	 * The Parlour — public types.
3	 *
4	 * These types form the contract between The Parlour apparatus and all
5	 * callers (CLI consult command, clockworks convene handlers, etc.).
6	 * No implementation details.
7	 *
8	 * See: docs/architecture/apparatus/parlour.md
9	 */
10	
11	import type { SessionResult, SessionChunk } from '@shardworks/animator-apparatus';
12	
13	// ── Conversation document (Stacks) ──────────────────────────────────
14	
15	export interface ConversationDoc {
16	  id: string;
17	  status: 'active' | 'concluded' | 'abandoned';
18	  kind: 'consult' | 'convene';
19	  topic: string | null;
20	  turnLimit: number | null;
21	  createdAt: string;
22	  endedAt: string | null;
23	  eventId: string | null;
24	  participants: ParticipantRecord[];
25	  /** Stored once at creation — all turns must use the same cwd for --resume. */
26	  cwd: string;
27	  /** Index signature required by BookEntry. */
28	  [key: string]: unknown;
29	}
30	
31	export interface ParticipantRecord {
32	  /** Stable participant id (generated at creation). */
33	  id: string;
34	  kind: 'anima' | 'human';
35	  name: string;
36	  /** Anima id, resolved at creation time. Null for human participants. */
37	  animaId: string | null;
38	  /**
39	   * Provider session id for --resume. Updated after each turn so
40	   * the next turn can continue the provider's conversation context.
41	   */
42	  providerSessionId: string | null;
43	}
44	
45	// ── Turn tracking ───────────────────────────────────────────────────
46	
47	/**
48	 * Internal turn record stored in the turns book.
49	 * One entry per takeTurn() call — both human and anima turns.
50	 */
51	export interface TurnDoc {
52	  id: string;
53	  conversationId: string;
54	  turnNumber: number;
55	  participantId: string;
56	  participantName: string;
57	  participantKind: 'anima' | 'human';
58	  /** The message passed to this turn (human message or inter-turn context). */
59	  message: string | null;
60	  /** Session id from The Animator (null for human turns). */
61	  sessionId: string | null;
62	  startedAt: string;
63	  endedAt: string | null;
64	  /** Index signature required by BookEntry. */
65	  [key: string]: unknown;
66	}
67	
68	// ── Request / Result types ──────────────────────────────────────────
69	
70	export interface CreateConversationRequest {
71	  /** Conversation kind. */
72	  kind: 'consult' | 'convene';
73	  /** Seed topic or prompt. Used as the initial message for the first turn. */
74	  topic?: string;
75	  /** Maximum allowed turns (anima turns only). Null = unlimited. */
76	  turnLimit?: number;
77	  /** Participants in the conversation. */
78	  participants: ParticipantDeclaration[];
79	  /** Working directory — persists for the conversation's lifetime. */
80	  cwd: string;
81	  /** Triggering event id, for conversations started by clockworks. */
82	  eventId?: string;
83	}
84	
85	export interface ParticipantDeclaration {
